import { Injectable, signal } from '@angular/core';
import { Order, CartItem } from '../models';

/**
 * Order service — checkout + history.
 *
 * Data contract: `orders` is a signal<Order[]> seeded with one demo order so history renders.
 * The mockup_cleaner clears it to signal<Order[]>([]); the service_agent wires it to
 * order-api.service.ts (GET /orders, POST /orders, GET /orders/admin/all).
 */
@Injectable({ providedIn: 'root' })
export class OrderService {
  readonly orders = signal<Order[]>([
    {
      id: 'ord-1042',
      userId: 'demo-shopper',
      status: 'shipped',
      shipName: 'Demo Shopper',
      shipAddress: '221B Baker Street, London',
      totalCents: 26800,
      createdAt: '2026-07-04T14:32:00.000Z',
      userEmail: 'shopper@demo',
      items: [
        {
          id: 'oi-1',
          productId: 'p-aurora-headphones',
          qty: 1,
          unitPriceCents: 18900,
          product: {
            id: 'p-aurora-headphones',
            name: 'Aurora Wireless Headphones',
            description: '',
            priceCents: 18900,
            imageUrl: 'https://picsum.photos/seed/aurora-headphones/120/120',
            stockQty: 24,
          },
        },
        {
          id: 'oi-2',
          productId: 'p-nimbus-speaker',
          qty: 1,
          unitPriceCents: 7900,
          product: {
            id: 'p-nimbus-speaker',
            name: 'Nimbus Portable Speaker',
            description: '',
            priceCents: 7900,
            imageUrl: 'https://picsum.photos/seed/nimbus-speaker/120/120',
            stockQty: 40,
          },
        },
      ],
    },
  ]);

  getById(id: string): Order | undefined {
    return this.orders().find((o) => o.id === id);
  }

  /** Simulates POST /orders — snapshots cart items into a new order. */
  placeOrder(items: CartItem[], shipName: string, shipAddress: string): Order {
    const totalCents = items.reduce((sum, i) => sum + i.qty * i.product.priceCents, 0);
    const order: Order = {
      id: `ord-${1043 + this.orders().length}`,
      userId: 'demo-shopper',
      status: 'placed',
      shipName,
      shipAddress,
      totalCents,
      createdAt: '2026-07-11T00:00:00.000Z',
      userEmail: 'shopper@demo',
      items: items.map((i, idx) => ({
        id: `oi-new-${idx}`,
        productId: i.productId,
        qty: i.qty,
        unitPriceCents: i.product.priceCents,
        product: i.product,
      })),
    };
    this.orders.update((list) => [order, ...list]);
    return order;
  }
}
